      {'label': '8A', 'value': '8A'}, {'label': '8B', 'value': '8B'},
      {'label': '8C', 'value': '8C'}, {'label': '8D', 'value': '8D'},
      {'label': '— Kelas 9 —', 'value': '__sep9__'},
      {'label': '9A', 'value': '9A'}, {'label': '9B', 'value': '9B'},
      {'label': '9C', 'value': '9C'}, {'label': '9D', 'value': '9D'},
