            ),
        ]),

        const SizedBox(height: 30),
      ]),
    );
  }

  // Render LaTeX inline
  Widget _renderLatex(String text) {
    final parts = <InlineSpan>[];
    final reg = RegExp(r'\$([^$]+)\$');
    int last = 0;
    for (final m in reg.allMatches(text)) {
      if (m.start > last) {
        parts.add(TextSpan(text: text.substring(last, m.start),
            style: const TextStyle(fontSize: 13)));
      }
      parts.add(WidgetSpan(
        alignment: PlaceholderAlignment.middle,
        child: Math.tex(m.group(1)!,
            textStyle: const TextStyle(fontSize: 13),
            onErrorFallback: (e) => Text(m.group(0)!,
                style: const TextStyle(fontSize: 13, color: Colors.red))),
      ));
      last = m.end;
    }
    if (last < text.length) {
      parts.add(TextSpan(text: text.substring(last),
          style: const TextStyle(fontSize: 13)));
    }
    return Text.rich(TextSpan(children: parts));
  }

  // Pilih gambar dari file
  Future<void> _pickGambar(SoalDraft s) async {
    final result = await FilePicker.platform.pickFiles(
        type: FileType.image, withData: true);
    if (result != null && result.files.single.bytes != null) {
      setState(() => s.gambarBase64 = base64Encode(result.files.single.bytes!));
    }
  }
}

class ExamHistoryScreen extends StatefulWidget {
  final ExamData exam;
  const ExamHistoryScreen({super.key, required this.exam});
  @override
  State<ExamHistoryScreen> createState() => _ExamHistoryScreenState();
}

class _ExamHistoryScreenState extends State<ExamHistoryScreen> {
  String _filterStatus = "semua";
  String _search = "";
  int _tabIndex = 0; // 0=Peserta, 1=Statistik

  ExamData get exam => widget.exam;

  Color _statusColor(String s) {
    switch (s) {
      case 'selesai': return Colors.green;
      case 'melanggar': return Colors.red;
      case 'mengerjakan': return Colors.indigo;
      default: return Colors.grey;
    }
  }

  IconData _statusIcon(String s) {
    switch (s) {
      case 'selesai': return Icons.check_circle;
      case 'melanggar': return Icons.warning;
      case 'mengerjakan': return Icons.edit;
      default: return Icons.schedule;
    }
  }

  String _statusLabel(String s) {
    switch (s) {
      case 'selesai': return 'SELESAI';
      case 'melanggar': return 'MELANGGAR';
      case 'mengerjakan': return 'MENGERJAKAN';
      default: return 'BELUM MULAI';
    }
  }

  Widget _filterChip(String value, String label, Color color) {
    final selected = _filterStatus == value;
    return GestureDetector(
      onTap: () => setState(() => _filterStatus = value),
      child: Container(
        padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 7),
        decoration: BoxDecoration(
          color: selected ? color : Colors.grey.shade100,
          borderRadius: BorderRadius.circular(20),
          border: Border.all(color: selected ? color : Colors.grey.shade300),
        ),
        child: Text(label,
            style: TextStyle(
                color: selected ? Colors.white : Colors.grey.shade700,
                fontSize: 12,
                fontWeight: FontWeight.w500)),
      ),
    );
  }

  Widget _miniChip(String label, Color color) {
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
      decoration: BoxDecoration(
          color: color.withValues(alpha: 0.15),
          borderRadius: BorderRadius.circular(10)),
      child: Text(label,
          style: TextStyle(color: color, fontSize: 10, fontWeight: FontWeight.w600)),
    );
  }

  Widget _statusBadge(ExamData e) {
    Color c;
    String label;
    if (e.isOngoing) {
      c = Colors.green;
      label = "BERLANGSUNG";
    } else if (e.sudahSelesai) {
      c = Colors.grey;
      label = "SELESAI";
    } else {
      c = Colors.orange;
      label = "BELUM MULAI";
    }
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 4),
      decoration: BoxDecoration(color: c, borderRadius: BorderRadius.circular(20)),
      child: Text(label, style: const TextStyle(color: Colors.white, fontSize: 10)),
    );
  }

