                    radius: 55,
                  ),
                  if (melanggar > 0) PieChartSectionData(
                    color: Colors.red,
                    value: melanggar.toDouble(),
                    title: "$melanggar",
                    titleStyle: const TextStyle(color: Colors.white, fontSize: 12, fontWeight: FontWeight.bold),
                    radius: 55,
                  ),
                  if (belum > 0) PieChartSectionData(
                    color: Colors.grey,
                    value: belum.toDouble(),
