// Model soal draft untuk editor
class SoalDraft {
  TipeSoal tipe;
  String pertanyaan;
  String? gambarBase64; // base64 gambar soal
  List<String> pilihan; // untuk PG: ["Teks A", "Teks B", ...]
  String kunciJawaban;
  int skor;

  SoalDraft({
    this.tipe = TipeSoal.pilihanGanda,
    this.pertanyaan = '',
    this.gambarBase64,
    List<String>? pilihan,
    this.kunciJawaban = '',
    this.skor = 1,
  }) : pilihan = pilihan ?? ['', '', '', ''];

