                          style: ElevatedButton.styleFrom(
                              backgroundColor: const Color(0xFF0F172A),
                              foregroundColor: Colors.white),
                          onPressed: () => setState(() => _currentIndex++),
                          icon: const Icon(Icons.arrow_forward, size: 16),
                          label: const Text("Selanjutnya"),
