/// Chip pemilih AI provider di Settings
Widget _aiProviderChip(String value, String label, String current, IconData icon) {
  final selected = value == current;
  return GestureDetector(
    onTap: () => FirebaseFirestore.instance
        .collection('settings')
        .doc('app_config')
        .set({'ai_provider': value}, SetOptions(merge: true)),
    child: AnimatedContainer(
      duration: const Duration(milliseconds: 200),
      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
      decoration: BoxDecoration(
        color: selected ? Colors.purple.shade700 : Colors.grey.shade100,
        borderRadius: BorderRadius.circular(20),
        border: Border.all(
          color: selected ? Colors.purple.shade700 : Colors.grey.shade300,
        ),
      ),
      child: Row(mainAxisSize: MainAxisSize.min, children: [
        Icon(icon, size: 14,
            color: selected ? Colors.white : Colors.grey.shade600),
        const SizedBox(width: 5),
        Text(label,
            style: TextStyle(
              fontSize: 12,
              fontWeight: FontWeight.w600,
              color: selected ? Colors.white : Colors.grey.shade700,
            )),
      ]),
    ),
  );
}

Widget _buildThemeSwitcher() {
  return StatefulBuilder(
    builder: (ctx, setSt) {
      final themes = BMTheme.values;
      final themeColors = {
        BMTheme.navy:   const Color(0xFF0D1117),
        BMTheme.dark:   const Color(0xFF000000),
        BMTheme.ocean:  const Color(0xFF0C1A3E),
        BMTheme.forest: const Color(0xFF0A1F12),
        BMTheme.purple: const Color(0xFF130A2A),
        BMTheme.rose:   const Color(0xFF1A0510),
      };
      return Padding(
        padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            const Row(children: [
              Icon(Icons.palette_outlined, size: 16, color: Colors.grey),
              SizedBox(width: 6),
              Text('Tema Aplikasi', style: TextStyle(fontSize: 12, fontWeight: FontWeight.bold, color: Colors.grey)),
            ]),
            const SizedBox(height: 8),
            ValueListenableBuilder<BMTheme>(
              valueListenable: _themeNotifier,
              builder: (_, current, __) => Wrap(
                spacing: 8,
                runSpacing: 8,
                children: themes.map((t) {
                  final isSelected = current == t;
                  return GestureDetector(
                    onTap: () async {
                      _themeNotifier.value = t;
                      setSt(() {});
                      final prefs = await SharedPreferences.getInstance();
                      await prefs.setString('app_theme', t.name);
                    },
                    child: Tooltip(
                      message: BMThemePresets.name(t),
                      child: Container(
                        width: 32,
                        height: 32,
                        decoration: BoxDecoration(
                          color: themeColors[t],
                          shape: BoxShape.circle,
                          border: isSelected
                              ? Border.all(color: Colors.white, width: 3)
                              : Border.all(color: Colors.transparent, width: 2),
                          boxShadow: isSelected
                              ? [BoxShadow(color: themeColors[t]!.withValues(alpha: 0.6), blurRadius: 6, spreadRadius: 1)]
                              : null,
                        ),
                        child: isSelected
                            ? const Icon(Icons.check, color: Colors.white, size: 14)
                            : null,
                      ),
                    ),
                  );
                }).toList(),
              ),
            ),
          ],
        ),
      );
    },
  );
}


// ============================================================
// PASSWORD RESET WIDGET
// ============================================================
class PasswordResetWidget extends StatefulWidget {
  const PasswordResetWidget({super.key});
  @override
  State<PasswordResetWidget> createState() => _PasswordResetWidgetState();
}

class _PasswordResetWidgetState extends State<PasswordResetWidget> {
  final _searchCtrl = TextEditingController();
  final _newPassCtrl = TextEditingController();
  bool _searching = false;
  bool _saving = false;
  bool _obscure = true;
  UserAccount? _found;
  String? _notFound;

  void _search() async {
    final q = _searchCtrl.text.trim();
    if (q.isEmpty) return;
    setState(() {
      _searching = true;
      _found = null;
      _notFound = null;
    });
    try {
      // Cari by username
      var snap = await FirebaseFirestore.instance
          .collection('users')
          .where('username', isEqualTo: q)
          .limit(1)
          .get();
      if (snap.docs.isNotEmpty) {
        setState(() {
          _found = UserAccount.fromFirestore(snap.docs.first);
          _searching = false;
        });
        return;
      }
      // Cari by nama
      snap = await FirebaseFirestore.instance
          .collection('users')
          .where('nama', isEqualTo: q)
          .limit(1)
          .get();
      if (snap.docs.isNotEmpty) {
        setState(() {
          _found = UserAccount.fromFirestore(snap.docs.first);
          _searching = false;
        });
      } else {
        setState(() {
          _notFound = "Akun \"$q\" tidak ditemukan.";
          _searching = false;
        });
      }
    } catch (e) {
      setState(() {
        _notFound = "Terjadi kesalahan pencarian.";
        _searching = false;
      });
    }
  }

  void _save() async {
    if (_found == null || _newPassCtrl.text.trim().isEmpty) return;
    setState(() => _saving = true);
    await FirebaseFirestore.instance
        .collection('users')
        .doc(_found!.id)
        .update({'password': _newPassCtrl.text.trim()});
    setState(() {
      _saving = false;
      _found = null;
      _newPassCtrl.clear();
      _searchCtrl.clear();
      _notFound = null;
    });
    if (mounted) {
      ScaffoldMessenger.of(context).showSnackBar(const SnackBar(
        content: Text("Password berhasil diubah!"),
        backgroundColor: Colors.green,
      ));
    }
  }

  @override
  Widget build(BuildContext context) =>
      Column(crossAxisAlignment: CrossAxisAlignment.start, children: [
        Row(children: [
          Expanded(
            child: TextField(
              controller: _searchCtrl,
              decoration: InputDecoration(
                labelText: "Username atau Nama",
                border: OutlineInputBorder(
                    borderRadius: BorderRadius.circular(10)),
                prefixIcon: const Icon(Icons.search),
              ),
              onSubmitted: (_) => _search(),
            ),
          ),
          const SizedBox(width: 10),
          ElevatedButton(
            style: ElevatedButton.styleFrom(
                backgroundColor: const Color(0xFF0F172A),
                foregroundColor: Colors.white),
            onPressed: _searching ? null : _search,
            child: _searching
                ? const SizedBox(
                width: 18,
                height: 18,
                child: CircularProgressIndicator(
                    color: Colors.white, strokeWidth: 2))
                : const Text("CARI"),
          ),
        ]),
        if (_notFound != null) ...[
          const SizedBox(height: 10),
          Row(children: [
            const Icon(Icons.error_outline, color: Colors.red, size: 16),
            const SizedBox(width: 6),
            Text(_notFound!,
                style: const TextStyle(color: Colors.red, fontSize: 13)),
          ]),
        ],
        if (_found != null) ...[
          const SizedBox(height: 14),
          Container(
            padding: const EdgeInsets.all(14),
            decoration: BoxDecoration(
              color: Colors.blue.shade50,
              borderRadius: BorderRadius.circular(10),
              border: Border.all(color: Colors.blue.shade200),
            ),
            child: Column(

              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Row(children: [
                  const Icon(Icons.check_circle,
                      color: Colors.green, size: 16),
                  const SizedBox(width: 6),
                  Text(_found!.nama,
                      style: const TextStyle(
                          fontWeight: FontWeight.bold, fontSize: 14)),
                ]),
                const SizedBox(height: 2),
                Text(
                    "Username: ${_found!.username}  •  Role: ${_found!.role}  •  Kelas: ${_found!.kode}",
                    style: const TextStyle(
                        color: Colors.grey, fontSize: 12)),
                const SizedBox(height: 14),
                Row(children: [
                  Expanded(
                    child: TextField(
                      controller: _newPassCtrl,
                      obscureText: _obscure,
                      decoration: InputDecoration(
                        labelText: "Password Baru",
                        border: OutlineInputBorder(
                            borderRadius: BorderRadius.circular(10)),
                        suffixIcon: IconButton(
                          icon: Icon(_obscure
                              ? Icons.visibility
                              : Icons.visibility_off),
                          onPressed: () =>
                              setState(() => _obscure = !_obscure),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(width: 10),
                  ElevatedButton.icon(
                    style: ElevatedButton.styleFrom(
                        backgroundColor: Colors.teal,
                        foregroundColor: Colors.white),
                    onPressed: _saving ? null : _save,
                    icon: _saving
                        ? const SizedBox(
                        width: 16,
                        height: 16,
                        child: CircularProgressIndicator(
                            color: Colors.white, strokeWidth: 2))
                        : const Icon(Icons.save),
                    label: const Text("SIMPAN"),
                  ),
                ]),
              ],
            ),
          ),
        ],
      ]);
}

